        private static SqlCommand SyncCommadParameters(SqlCommand sqlCommandParam, SqlCommand sqlCommand1)
        {
            List<SqlParameter> parameters = new List<SqlParameter>();

            // Loop through each parameter in sqlCommandParam and cast to SqlParameter
            foreach (SqlParameter p in sqlCommandParam.Parameters)
            {
                // Deep clone the SqlParameter and add it to sqlCommand1
                sqlCommand1.Parameters.Add(CloneSqlParameter(p));
            }

            // If needed, add cloned parameters to a list and add them later (as your code suggests)
            foreach (SqlParameter p in parameters)
            {
                sqlCommand1.Parameters.Add(p);
            }

            sqlCommand1.CommandTimeout = 500;

            return sqlCommand1;
        }

        // Deep cloning method for SqlParameter
        public static SqlParameter CloneSqlParameter(SqlParameter original)
        {
            if (original == null)
                throw new ArgumentNullException(nameof(original));

            SqlParameter clone = new SqlParameter
            {
                ParameterName = original.ParameterName,
                SqlDbType = original.SqlDbType,
                Direction = original.Direction,
                Size = original.Size,
                Value = original.Value,
                IsNullable = original.IsNullable,
                Precision = original.Precision,
                Scale = original.Scale,
                SourceColumn = original.SourceColumn,
                SourceColumnNullMapping = original.SourceColumnNullMapping,
                SourceVersion = original.SourceVersion,
                TypeName = original.TypeName,
                UdtTypeName = original.UdtTypeName,
                XmlSchemaCollectionDatabase = original.XmlSchemaCollectionDatabase,
                XmlSchemaCollectionName = original.XmlSchemaCollectionName,
                XmlSchemaCollectionOwningSchema = original.XmlSchemaCollectionOwningSchema
            };

            return clone;
        }

