        protected void GridEstimate_OnNeedDataSource(object source, GridNeedDataSourceEventArgs e)
        {
            if (base.IsPostBack)
            {
                DataSet estimateData = this.GetEstimateData(this.PageNumber);
                DataTable dt = SetEstReportColumns(estimateData);
                this.GridEstReport.DataSource = dt;
            }

        }
        protected void GridEstimate_PageIndexChanged(object sender, GridPageChangedEventArgs e)
        {
            this.Session["DeleteMsg"] = null;
            this.PageNumber = e.NewPageIndex + 1;
        }

        protected void GridEstimate_PageSizeChanged(object sender, GridPageSizeChangedEventArgs e)
        {
            this.Session["DeleteMsg"] = null;
            this.PageSize = e.NewPageSize;
        }

